CODE_EXAMPLE:
// Before (smell)
class Animal {
  void fly() { ... }
  void walk() { ... }
}

class Dog extends Animal {
  // fly() is inherited but makes no sense for a dog
}

// After (refactored - replace inheritance with delegation)
interface Walkable {
  void walk();
}

class Dog implements Walkable {
  public void walk() { ... }
}

UNIT_TEST_EXAMPLE:
@Test
public void testRefusedBequest() {
  Dog dog = new Dog();
  dog.walk();
  // dog does not have fly() anymore
}
